#include <bits/stdc++.h>
using namespace std;
int main()
{
    long long a,b,l,g,o=0;
    cin>>a>>b;
    long long c[a+1];
    for(int i=0;i<=a;i++)
        {
            c[i]=1;
        }
    for(int i=0;i<b;i++)
        {
            cin>>l>>g;
            for(int j=l;j<=g;j++)
                {
                    c[j]=0;
                }
        }
    for(int i=0;i<=a;i++)
        {
            o+=c[i];
        }
    cout<<o;
    return 0;
}
